import { ErrorType } from './error-type';
/**
 * Serialized http exception with response status
 */
export interface HttpSerializedError {
    name: string;
    message: string;
    stack?: string;
    type: ErrorType.HTTP;
    status: number;
    /** @deprecated */
    body?: unknown;
    errorRef?: string;
    cause?: any;
    details?: any;
}
